def majority_elements_n_over_3(nums):
    cand1 = cand2 = None
    c1 = c2 = 0
    for x in nums:
        if x == cand1:
            c1 += 1
        elif x == cand2:
            c2 += 1
        elif c1 == 0:
            cand1, c1 = x, 1
        elif c2 == 0:
            cand2, c2 = x, 1
        else:
            c1 -= 1
            c2 -= 1
    res = []
    n = len(nums)
    if cand1 is not None and nums.count(cand1) > n // 3:
        res.append(cand1)
    if cand2 is not None and cand2 != cand1 and nums.count(cand2) > n // 3:
        res.append(cand2)
    return res

